mapper.select:
/* adm-role-applicationbyrole-sql-oracle.xml - selectTAdminMstRoxapgt */
	SELECT '0' AS CHK
	       ,APKEY
	       ,ROKEY
	  FROM TADMIN_MST_ROXAPGT
	 WHERE ROKEY = #{rokey}

mapper.insert:
/* adm-role-applicationbyrole-sql-oracle.xml - insertTAdminMstRoxapgt */
INSERT INTO TADMIN_MST_ROXAPGT (
	 ROKEY
	 ,APKEY
	 ,INSERTURKEY
	 ,INSERTDATE
	 ,UPDATEURKEY
	 ,UPDATEDATE
) VALUES ( 
	 #{rokey}
	 ,#{apkey}
	 ,#{surkey}
	 ,#{sysdate}
	 ,#{surkey}
	 ,#{sysdate}

)

mapper.delete:
/* adm-role-applicationbyrole-sql-oracle.xml - deleteTAdminMstRoxapgt */
DELETE 
  FROM TADMIN_MST_ROXAPGT
 WHERE ROKEY = #{rokey}
   AND APKEY = #{apkey}
